var e=[{id:`L2_1`,type:`dialog`,speaker:`XIAOLIN_ALT_NULL_NULL`,text:{KOREA:`적 전차부대 격파! 3시 방향, 증원군 포착!`,JPN:`敵の戦車部隊を撃破！　3時方向、援軍発見！`,ENG:`Enemy armor unit destroyed! Reinforcements spotted, three o' clock!`,TWN:`敵方戰車部隊擊破！3點鐘方向，確認到援軍！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`전방 엄폐물까지 약진! 소빈이는 제압사격 개시!`,JPN:`前方の遮蔽物まで速やかに進行！　コハルは制圧射撃を開始！`,ENG:`Advance to the cover ahead! Sobin, lay down suppressing fire!`,TWN:`跑到前方遮蔽物！素蘋開始壓制射擊！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:{char_id:`KIMSOBIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L6_1`,type:`dialog`,speaker:`KIMSOBIN_ALT_NULL_NULL`,text:{KOREA:`으, 응!!`,JPN:`は、はい！！`,ENG:`R-roger!`,TWN:`好、好！！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:{char_id:`KIMSOBIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L11_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`젠장, 얼마나 더 가야 하는 거야?!`,JPN:`ちくしょう、あとどれくらい行けばいいんだ！？`,ENG:`Dang it, are we there yet?!`,TWN:`可惡，到底還要走多久啊？！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`거의 다 왔어! 이제 저기만 돌파하면 합류지점이야!`,JPN:`もうすぐよ！　あそこさえ突破すれば合流地点だから！`,ENG:`Almost! The rendezvous point is right behind there!`,TWN:`快到了！現在只要突破那邊就能到達會合地點了！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`비켜, 이 자식들아!! 우린 바쁘다고!`,JPN:`どけよ、この野郎！　俺らは忙しいんだよ！`,ENG:`Out of our way you bastard! We're busy!`,TWN:`滾開，你們這些混蛋！！我們現在很忙！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`우뢰야압!!`,JPN:`おらああ！！`,ENG:`Graah!`,TWN:`雷霆一擊！！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`XIAOLIN_ALT_NULL_NULL`,text:{KOREA:`혼자 튀어나가지 마, 멧돼지야!`,JPN:`一人で先走らないでよ、イノシシ！`,ENG:`Don’t rush out there by yourself, you boar!`,TWN:`妳別一個人衝那麼前面啊，野豬！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`포인트맨이 안 튀어나가면 누가 튀어나가냐, 이 닭대가리야?! 엄호나 잘해!`,JPN:`先導役なんだから先走って当たり前だろ、この鳥頭が！　それよりちゃんと援護しろよ！`,ENG:`Of course I’m rushing out! I’m supposed to take point, you birdbrain! Just cover me, will you?`,TWN:`主力隊員不衝在前面，那誰要在前面啊，妳這個雞腦袋？！乖乖做好妳的掩護工作！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`XIAOLIN_ALT_NULL_NULL`,text:{KOREA:`아니 저 멍청이가! 대체 전열이란 걸 뭐로 생각하는......`,JPN:`なっ、バカじゃないの？　戦列をいったい何だと思って……`,ENG:`That idiot! Stay in formation, you reckless-`,TWN:`這個笨蛋！到底把隊伍當成什麼了……`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`XIAOLIN_ALT_NULL_NULL`,text:{KOREA:`어?`,JPN:`え？`,ENG:`Huh?`,TWN:`奇怪？`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`XIAOLIN_ALT_NULL_NULL`,text:{KOREA:`잠깐, 저기 뭔가 보였는데?`,JPN:`ちょっと待って、あそこに何か見えて？`,ENG:`Hang on... I just saw something over there...`,TWN:`等一下，那邊好像有什麼？`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`XIAOLIN_ALT_NULL_NULL`,text:{KOREA:`전방! 고 에너지체 접근!`,JPN:`前方！　高エネルギー体が接近！`,ENG:`Incoming! High energy projectile!`,TWN:`前方！有高能量體接近！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`XIAOLIN_ALT_NULL_NULL`,text:{KOREA:`위험해! 대장!`,JPN:`危ない！　隊長！`,ENG:`Watch out! Cap!`,TWN:`危險！隊長！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`전 대원 충격 대비!`,JPN:`全隊員、衝撃に備えよ！`,ENG:`Everyone brace for impact!`,TWN:`全體隊員準備承受衝擊！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`유진아, 엎드려!!`,JPN:`シロコ、伏せて！！`,ENG:`Get down, Eujin!`,TWN:`劉珍，趴下！！`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};